    int rc = ____(mem, (size_t)hp_size, ____);
    printf("madvise HUGEPAGE: %s\n", rc == 0 ? "ok" : "unsupported");
    memset(mem, 'H', (size_t)hp_size);
    printf("Filled 2MB: %c...%c\n", mem[0], mem[hp_size - 1]);
    ____(mem, (size_t)hp_size);
    return 0;
