#include <stdio.h>
#include <sys/mman.h>
#include <unistd.h>
#include <string.h>

#ifndef MAP_HUGE_2MB
#define MAP_HUGE_2MB (21 << MAP_HUGE_SHIFT)
#endif

int main(void) {
    long ps = getpagesize();
    long hp_size = 2L * 1024 * 1024; /* 2MB */
    printf("Standard page: %ld bytes\n", ps);
    printf("Huge page: %ld bytes\n", hp_size);
    printf("Ratio: %ld standard pages per huge page\n", hp_size / ps);
    long tlb_entries = 1024;
    long coverage_std = tlb_entries * ps;
    long coverage_hp = tlb_entries * hp_size;
    printf("TLB coverage (standard): %ld MB\n", coverage_std / (1024 * 1024));
    printf("TLB coverage (huge): %ld MB\n", coverage_hp / (1024 * 1024));
    char *mem = (char *)mmap(NULL, hp_size,
        PROT_READ | PROT_WRITE,
        MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (mem == MAP_FAILED) { perror("mmap"); return 1; }
    int rc = madvise(mem, (size_t)hp_size, MADV_HUGEPAGE);
    printf("madvise HUGEPAGE: %s\n", rc == 0 ? "ok" : "unsupported");
    memset(mem, 'H', (size_t)hp_size);
    printf("Filled 2MB: %c...%c\n", mem[0], mem[hp_size - 1]);
    munmap(mem, (size_t)hp_size);
    return 0;
}

